import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';

export interface Message {
  id: string;
  user_id: string;
  original_text: string;
  amount: number | null;
  sender_name: string | null;
  transaction_date: string | null;
  mpesa_code: string | null;
  sms_sender: string;
  is_read: boolean;
  received_timestamp: string;
  created_at: string;
}

export const useMessages = (userId: string | undefined) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [loading, setLoading] = useState(true);
  const [unreadCount, setUnreadCount] = useState(0);

  const fetchMessages = async () => {
    if (!userId) return;

    try {
      const { data, error } = await supabase
        .from('messages')
        .select('*')
        .eq('user_id', userId)
        .order('received_timestamp', { ascending: false });

      if (error) throw error;

      setMessages(data || []);
      setUnreadCount(data?.filter(m => !m.is_read).length || 0);
    } catch (error: any) {
      toast.error('Failed to fetch messages');
      console.error('Error fetching messages:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMessages();
  }, [userId]);

  // Set up real-time subscription
  useEffect(() => {
    if (!userId) return;

    const channel = supabase
      .channel('messages-changes')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'messages',
          filter: `user_id=eq.${userId}`,
        },
        (payload) => {
          console.log('Real-time update:', payload);
          
          if (payload.eventType === 'INSERT') {
            setMessages(prev => [payload.new as Message, ...prev]);
            setUnreadCount(prev => prev + 1);
            toast.success('New MPESA message received!');
          } else if (payload.eventType === 'UPDATE') {
            setMessages(prev => 
              prev.map(msg => msg.id === payload.new.id ? payload.new as Message : msg)
            );
            fetchMessages(); // Refresh unread count
          } else if (payload.eventType === 'DELETE') {
            setMessages(prev => prev.filter(msg => msg.id !== payload.old.id));
            fetchMessages();
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [userId]);

  const markAsRead = async (messageId: string) => {
    try {
      const { error } = await supabase
        .from('messages')
        .update({ is_read: true })
        .eq('id', messageId);

      if (error) throw error;

      setMessages(prev =>
        prev.map(msg => msg.id === messageId ? { ...msg, is_read: true } : msg)
      );
      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch (error: any) {
      console.error('Error marking message as read:', error);
    }
  };

  const deleteMessages = async (ids: string[]) => {
    try {
      if (ids.length === 0) return;
      const { error } = await supabase
        .from('messages')
        .delete()
        .in('id', ids);

      if (error) throw error;

      // Refresh list to ensure counts are accurate
      await fetchMessages();
      toast.success(`Deleted ${ids.length} message${ids.length > 1 ? 's' : ''}`);
    } catch (error: any) {
      console.error('Error deleting messages:', error);
      toast.error('Failed to delete messages');
    }
  };

  return {
    messages,
    loading,
    unreadCount,
    markAsRead,
    refetch: fetchMessages,
    deleteMessages,
  };
};

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';

export interface Receipt {
  id: string;
  user_id: string;
  message_id: string;
  receipt_number: string;
  amount: number;
  sender_name: string;
  sender_phone: string;
  mpesa_code: string;
  transaction_date: string;
  created_at: string;
}

export const useReceipts = (userId: string | undefined) => {
  const [receipts, setReceipts] = useState<Receipt[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchReceipts = async () => {
    if (!userId) {
      setReceipts([]);
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('receipts')
        .select('*')
        .eq('user_id', userId)
        .order('created_at', { ascending: false });

      if (error) throw error;

      setReceipts(data || []);
    } catch (error) {
      console.error('Error fetching receipts:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchReceipts();

    if (!userId) return;

    // Subscribe to real-time updates
    const channel = supabase
      .channel('receipts')
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'receipts',
          filter: `user_id=eq.${userId}`,
        },
        (payload) => {
          console.log('New receipt:', payload);
          setReceipts((current) => [payload.new as Receipt, ...current]);
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [userId]);

  return { receipts, loading, refetch: fetchReceipts };
};

